SELECT line_name
FROM transit_lines
WHERE active_status = 1;

SELECT SUM(total_passengers) AS total_monthly_passengers
FROM ridership_data
WHERE line_id = 0 AND year = 2014 AND month = 8;

SELECT line_id, total_passengers, peak_hour
FROM ridership_data
WHERE line_id = 1 AND year = 2014 AND month = 8 AND day = 23;

SELECT COUNT(*) AS total_delays
FROM transit_status
WHERE line_id = 1 AND station_id = 1 AND status = 'Delayed';

SELECT MIN(metric_value) AS worst_on_time_rate
FROM reporting_metrics
WHERE line_id = 1 AND metric_name = 'On-time Rate';

SELECT metric_name
FROM reporting_metrics
WHERE line_id = 1 AND year = 2014;

SELECT COUNT(line_id) AS active_lines_count
FROM transit_lines
WHERE active_status = 1;

SELECT MAX(last_updated) AS latest_update
FROM transit_lines
WHERE line_id = 1;
